// 1. Grab the current input (the response from the Poll Status HTTP node)
const statusResponse = $input.first().json;

// 2. Grab the data from the previous iteration (or initial submission)
// We use $json here which refers to the current item's incoming data
const previousData = $json;

// 3. Check for API-level errors
if (statusResponse.code !== 200) {
  throw new Error('Status check failed: ' + JSON.stringify(statusResponse));
}

const taskData = statusResponse.data;
const state = taskData?.state;

// CASE: SUCCESS
if (state === 'success') {
  let imageUrl = null;
  try { 
    const r = JSON.parse(taskData.resultJson || '{}'); 
    imageUrl = r.resultUrls?.[0]; 
  } catch(e) {
    throw new Error('Failed to parse resultJson');
  }

  if (!imageUrl) throw new Error('No image URL: ' + JSON.stringify(taskData));

  return [{ 
    json: { 
      ...previousData, 
      imageUrl, 
      imageStatus: 'completed', 
      shouldContinueImage: false 
    } 
  }];

// CASE: FAILED
} else if (state === 'fail') {
  throw new Error('Image gen failed: ' + (taskData.failMsg || 'Unknown API Error'));

// CASE: STILL PROCESSING (The Loop)
} else {
  const pollCount = (previousData.imagePollCount || 0) + 1;

  // Safety timeout: 40 polls * 15s wait = 10 minutes
  if (pollCount > 40) {
    throw new Error('Image timed out. Task: ' + (previousData.data?.taskId || 'Unknown ID'));
  }

  return [{ 
    json: { 
      ...previousData, // This keeps 'data': { 'taskId': '...' } alive
      imagePollCount: pollCount, 
      shouldContinueImage: true 
    } 
  }];
}

const allRows = $input.all().map(item => item.json);

// 1. CLEANING STEP: Create a version of every row with "Invisible-Proof" keys
const cleanRows = allRows.map(row => {
  const clean = {};
  for (let key in row) {
    // Strips all spaces, underscores, and invisible characters from header names
    const cleanKey = key.toLowerCase().replace(/[^a-z0-9]/g, '');
    clean[cleanKey] = row[key];
  }
  return clean;
});

// 2. SORTING: Using the cleaned key 'promptnumber'
cleanRows.sort((a, b) => {
  const numA = parseInt(a.promptnumber) || 0;
  const numB = parseInt(b.promptnumber) || 0;
  return numA - numB;
});

// 3. PROCESSING
return cleanRows.map((row, index) => {
  // Map cleaned keys to variables
  const genType = (row.generationtype || "").toString().toLowerCase();
  const videoPrompt = (row.videoprompt || "").toString().trim();
  const currentImageUrl = (row.imageurl || "").toString().trim();
  const promptNum = parseInt(row.promptnumber) || (index + 1);

  let tailImageUrl = null;
  let shouldGenerate = false;
  let skipReason = null;

  // LOGIC CHECK
  if (genType.includes("frame")) {
    const nextRow = cleanRows[index + 1];
    const nextImageUrl = nextRow ? (nextRow.imageurl || "").toString().trim() : null;

    if (nextImageUrl) {
      tailImageUrl = nextImageUrl;
      shouldGenerate = true;
    } else {
      skipReason = "End of chain: No Image URL found in next row.";
    }
  } else if (genType.includes("single")) {
    shouldGenerate = true;
  } else {
    skipReason = `Invalid Type: Found "${genType}" instead of 'single' or 'frame'`;
  }

  // FINAL BLOCKER CHECK
  if (!currentImageUrl) {
    shouldGenerate = false;
    skipReason = "Error: Image URL column is empty for this row.";
  }

  if (videoPrompt.length < 3) {
    shouldGenerate = false;
    skipReason = "Error: Video Prompt is empty or too short.";
  }

  return {
    json: {
      promptNumber: promptNum,
      videoPrompt,
      generationType: genType,
      imageUrl: currentImageUrl,
      tailImageUrl,
      shouldGenerate,
      skipReason: shouldGenerate ? "READY" : skipReason,
      // This helper helps you see what the "Clean" keys look like
      _detected_keys: Object.keys(row) 
    }
  };
});

const item = $input.first().json;

const input = {
  prompt: item.videoPrompt,
  image_url: item.imageUrl,
  duration: "5",
  negative_prompt: "blur, distort, and low quality",
  cfg_scale: 0.5
};

// ONLY add tail_image_url if the logic in the previous node found one
if (item.tailImageUrl) {
  input.tail_image_url = item.tailImageUrl;
}

return [{ 
  json: { 
    ...item, 
    requestBody: { 
      model: "kling/v2-5-turbo-image-to-video-pro", 
      input 
    } 
  } 
}];

const response = $input.first().json;
const promptData = $('Build Video Request Body').item.json;
if (response.code !== 200) throw new Error('Kie.ai video task failed: ' + JSON.stringify(response));
const taskId = response.data?.taskId;
if (!taskId) throw new Error('No taskId returned: ' + JSON.stringify(response));
return [{ json: { ...promptData, videoTaskId: taskId, videoPollCount: 0 } }];

const statusResponse = $input.first().json;
const previousData = $('Extract Video Task ID').item.json;
if (statusResponse.code !== 200) throw new Error('Video status failed: ' + JSON.stringify(statusResponse));
const taskData = statusResponse.data;
const state = taskData?.state;
if (state === 'success') {
  let videoUrl = null;
  try { const r = JSON.parse(taskData.resultJson || '{}'); videoUrl = r.resultUrls?.[0]; } catch(e) {}
  if (!videoUrl) throw new Error('No video URL: ' + JSON.stringify(taskData));
  return [{ json: { ...previousData, videoUrl, videoStatus: 'completed', shouldContinueVideo: false } }];
} else if (state === 'fail') {
  throw new Error('Video gen failed: ' + (taskData.failMsg || 'Unknown'));
} else {
  const pollCount = (previousData.videoPollCount || 0) + 1;
  if (pollCount > 60) throw new Error('Video timed out. Task: ' + previousData.videoTaskId);
  return [{ json: { ...previousData, videoPollCount: pollCount, shouldContinueVideo: true } }];
}

const currentItem = $input.first().json;
const currentPromptNum = parseInt(currentItem['Prompt Number'] || currentItem.promptNumber);

// Normalise field names — sheet reads use Title Case headers, appended items use camelCase
const promptText = currentItem['Prompt Text'] || currentItem.promptText || '';
const promptNumber = currentItem['Prompt Number'] || currentItem.promptNumber;
const generationType = currentItem['Generation Type'] || currentItem.generationType || '';
const projectID = currentItem['Project ID'] || currentItem.projectID || currentItem['Project Id'];
const row_number = currentItem.row_number;

// Master reference image - always included
const MASTER_REF = 'https://drive.google.com/uc?export=download&id=1NDIb54Y30a0-GrvrK_5h9vjYs12Nxacs';
let imageInputs = [MASTER_REF];

// If Frame-to-Frame, try to add the previous frame for consistency
if (generationType.toLowerCase() === 'frame to frame' && currentPromptNum > 1) {
  try {
    const processedItems = $('Update Sheet with Image URL').all().map(i => i.json);
    const prevItem = processedItems.find(i => parseInt(i['Prompt Number'] || i.promptNumber) === (currentPromptNum - 1));
    if (prevItem && (prevItem['Image URL'] || prevItem.imageUrl)) {
      imageInputs.push(prevItem['Image URL'] || prevItem.imageUrl);
    }
  } catch (e) {
    // Previous items not yet available
  }
}

return {
  json: {
    ...currentItem,
    // Explicitly set clean normalised keys so downstream nodes always find them
    promptText,
    promptNumber,
    generationType,
    projectID,
    row_number,
    calculatedImageInput: imageInputs
  }
};

