// Get all items from the Google Sheets node
const sheetItems = $('Get Projects').all();

// Calculate the new projectID (total rows + 1)
const projectID = sheetItems.length + 1;

// Get the form submission data
const formData = $('On form submission').first().json;

// Return the new projectID with form data
return [
  {
    json: {
      projectID: projectID,
      idea: formData.Idea,
      submittedAt: formData.submittedAt
    }
  }
];

const response = $input.first().json;
const loopData = $('VO Loop').item.json;
const requestId = response.request_id;
if (!requestId) throw new Error('No request_id returned: ' + JSON.stringify(response));
return [{ json: {
  ...loopData,
  promptNumber: loopData['Prompt Number'] || loopData.promptNumber,
  projectID: loopData['Project ID'] || loopData.projectID,
  voRequestId: requestId,
  voPollCount: 0
} }];

const statusResponse = $input.first().json;
const previousData = $('Extract VO Request ID').item.json;
const status = statusResponse.status;

if (status === 'COMPLETED') {
  return [{ json: { ...previousData, voStatus: 'completed', shouldContinueVO: false } }];
} else if (status === 'FAILED') {
  throw new Error('VO generation failed: ' + JSON.stringify(statusResponse));
} else {
  const pollCount = (previousData.voPollCount || 0) + 1;
  if (pollCount > 30) throw new Error('VO timed out after ' + pollCount + ' polls. Request: ' + previousData.voRequestId);
  return [{ json: { ...previousData, voPollCount: pollCount, shouldContinueVO: true } }];
}
